import React, { useEffect, useState } from 'react';

import { api } from '../api/api';

interface Product {
    id: number;
    name: string;
    description: string;
    image_url: string;
    category: string;
    price: number;
}

const CatalogPage: React.FC = () => {
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        api.getProducts()
            .then(data => {
                setProducts(data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setError('Не удалось загрузить каталог');
                setLoading(false);
            });
    }, []);

    if (loading) return <div className="page-shell text-center font-semibold text-graphite-500">Загрузка каталога...</div>;

    if (error) return <div className="page-shell text-center font-semibold text-red-600">{error}</div>;

    return (
        <div className="page-shell">
            <div className="mb-10">
                <h1 className="page-title">Каталог продукции</h1>
            </div>

            <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
                {products.map(product => (
                    <div key={product.id} className="card-hover overflow-hidden p-4">
                        <div className="relative overflow-hidden rounded-[1.25rem] bg-gradient-to-br from-graphite-50 to-white p-4">
                            <img
                                src={product.image_url || 'https://via.placeholder.com/300x200?text=Нет+изображения'}
                                alt={product.name}
                                className="h-52 w-full rounded-xl object-cover"
                            />
                            {product.category ? (
                                <span className="absolute left-5 top-5 rounded-full bg-white/90 px-3 py-1 text-xs font-bold text-factory-700 shadow-card">
                  {product.category}
                </span>
                            ) : null}
                        </div>

                        <div className="p-2 pt-5">
                            <h3 className="font-display text-2xl font-black leading-tight text-graphite-950">{product.name}</h3>
                            <p className="mt-3 line-clamp-3 text-sm leading-6 text-graphite-600">{product.description}</p>

                            <div className="mt-5 flex items-center justify-between gap-4 border-t border-graphite-100 pt-4">
                                <span className="text-2xl font-black text-factory-700">{product.price} ₽</span>
                                <span className="rounded-full bg-graphite-100 px-3 py-1 text-xs font-bold text-graphite-600">{product.category}</span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default CatalogPage;
